 11→const parseTextContentSafely = (content) => {
 12→    if(typeof content !== 'string' || !content.trim()){
 13→        return null;
 14→    }
 15→
 16→    const parsedData = ParseContent(content);
 17→    if(!parsedData || typeof parsedData !== 'object'){
 18→        return null;
 19→    }
 20→
 21→    return parsedData;
 22→}
