383→export const updateJournalService = async(content, title, journalId, userId) => {
384→    if(!journalId){
385→        console.error('journalid is undefined');
386→        throw {status: 400, error: 'journalId is undefined'}
387→    }
388→
389→    if(!userId){
390→        console.error('userId is undefined')
391→        throw({status: 400, error: 'userId is undefined'})
392→    }
393→
394→    const {data: existingJournal, error: existingJournalError} = await supabase
395→    .from('journals')
396→    .select('id, user_id, content, title, post_type')
397→    .eq('id', journalId)
398→    .eq('user_id', userId)
399→    .maybeSingle();
400→
401→    if(existingJournalError){
402→        console.error('failed to fetch existing journal for update', existingJournalError.message);
403→        throw {status: 500, error: 'failed to fetch existing journal for update'};
404→    }
405→
406→    if(!existingJournal){
407→        console.error('journal not found for update');
408→        throw {status: 404, error: 'journal not found for update'};
409→    }
410→
411→    const resolvedTitle = typeof title === 'string' && title.trim() ? title.trim() : existingJournal.title;
412→    if(!resolvedTitle){
413→        console.error('title is undefined');
414→        throw {status: 400, error: 'title is undefined'};
415→    }
416→
417→    let resolvedContent = existingJournal.content;
418→    if(typeof content === 'string' && content.trim()){
419→        resolvedContent = content;
420→    }
421→
422→    if(!resolvedContent){
423→        console.error('text content is missing for text post update');
424→        throw {status: 400, error: 'text content is missing for text post update'};
425→    }
426→
427→    const parseData = parseTextContentSafely(resolvedContent);
428→    if(!parseData){
429→        console.error('failed to parse text content for update');
430→        throw {status: 400, error: 'failed to parse text content for update'};
431→    }
432→
433→    const embeddingBody = parseData.wholeText || '';
434→    const preview_text = parseData.slicedText || '';
435→    const thumbnail_url = parseData.firstImage?.src || null;
436→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
437→    const embeddings = await GenerateEmbeddings(resolvedTitle, embeddingBody);
438→
439→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
440→        console.error('failed to generate embeddings')
441→        throw {status: 400, error: 'failed to generate embeddings'};
442→    }
443→
444→    const journalData = {
445→        content: resolvedContent,
446→        title: resolvedTitle,
447→        post_type: POST_TYPE_TEXT,
448→        embeddings: embeddings,
449→        preview_text,
450→        thumbnail_url,
451→        reading_time,
452→    }
453→
454→    const {data, error} = await supabase
455→    .from('journals')
456→    .update(journalData)
457→    .eq('id', journalId)
458→    .eq('user_id', userId)
459→
460→    if(error){
461→        console.error('supabase error while uploading content:', error.message);
462→        throw{status: 500, error: 'supabase error while uploading content'};
463→    }
464→
465→    // Non-fatal: send mention notifications on edit
466→    try {
467→        const mentionedUserIds = extractMentionUserIds(resolvedContent);
468→        const filtered = mentionedUserIds
469→            .filter(id => id !== userId)
470→            .slice(0, 50);
471→
472→        // Remove old mention notifications for this journal to avoid duplicates
473→        const { error: deleteError } = await supabase
474→            .from('notifications')
475→            .delete()
476→            .eq('type', 'mention')
477→            .eq('journal_id', journalId);
478→
479→        if (deleteError) console.error('[mentions] edit: clear old failed:', deleteError.message);
480→
481→        if (filtered.length > 0) {
482→            const notifRows = filtered.map(receiverId => ({
483→                sender_id: userId,
484→                receiver_id: receiverId,
485→                type: 'mention',
486→                journal_id: journalId,
487→                read: false
488→            }));
489→
490→            const { error: notifError } = await supabase
491→                .from('notifications')
492→                .insert(notifRows);
493→
494→            if (notifError) console.error('[mentions] edit: insert failed:', notifError.message);
495→        }
496→    } catch (mentionErr) {
497→        console.error('[mentions] edit error:', mentionErr?.message || mentionErr);
498→    }
499→
500→    return true;
501→}
