586→export const saveDraftService = async(content, title, userId, draftId = null, promptId = null) => {
587→    if(!userId){
588→        throw {status: 400, error: 'userId is undefined'};
589→    }
590→
591→    if(!content || typeof content !== 'string' || !content.trim()){
592→        throw {status: 400, error: 'content is required'};
593→    }
594→
595→    // Validate content is parseable JSON
596→    try {
597→        JSON.parse(content);
598→    } catch {
599→        throw {status: 400, error: 'content must be valid JSON'};
600→    }
601→
602→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
603→
604→    if(draftId){
605→        // Update existing draft — verify ownership
606→        const {data: existing, error: fetchError} = await supabase
607→            .from('journals')
608→            .select('id, user_id, status')
609→            .eq('id', draftId)
610→            .eq('user_id', userId)
611→            .eq('status', 'draft')
612→            .maybeSingle();
613→
614→        if(fetchError){
615→            console.error('failed to fetch draft for update:', fetchError.message);
616→            throw {status: 500, error: 'failed to fetch draft'};
617→        }
618→
619→        if(!existing){
620→            throw {status: 404, error: 'draft not found'};
621→        }
622→
623→        const {error: updateError} = await supabase
624→            .from('journals')
625→            .update({
626→                title: trimmedTitle,
627→                content: content,
628→                updated_at: new Date().toISOString(),
629→            })
630→            .eq('id', draftId)
631→            .eq('user_id', userId);
632→
633→        if(updateError){
634→            console.error('supabase error updating draft:', updateError.message);
635→            throw {status: 500, error: 'failed to update draft'};
636→        }
637→
638→        return {id: draftId};
639→    }
640→
641→    // Create new draft
642→    const payload = {
643→        user_id: userId,
644→        title: trimmedTitle,
645→        content: content,
646→        post_type: POST_TYPE_TEXT,
647→        status: 'draft',
648→    };
649→
650→    if(promptId){
651→        const parsedPromptId = parseInt(promptId, 10);
652→        if(!isNaN(parsedPromptId)){
653→            payload.prompt_id = parsedPromptId;
654→        }
655→    }
656→
657→    const {data: insertData, error: insertError} = await supabase
658→        .from('journals')
659→        .insert(payload)
660→        .select('id')
661→        .single();
662→
663→    if(insertError){
664→        console.error('supabase error creating draft:', insertError.message);
665→        throw {status: 500, error: 'failed to create draft'};
666→    }
667→
668→    return {id: insertData.id};
669→}
