685→
686→    if(fetchError){
687→        console.error('failed to fetch draft for publish:', fetchError.message);
688→        throw {status: 500, error: 'failed to fetch draft'};
689→    }
690→
691→    if(!draft){
692→        throw {status: 404, error: 'draft not found'};
693→    }
694→
695→    if(draft.status !== 'draft'){
696→        throw {status: 400, error: 'journal is not a draft'};
697→    }
698→
699→    const trimmedTitle = typeof draft.title === 'string' ? draft.title.trim() : '';
700→    if(!trimmedTitle){
701→        throw {status: 400, error: 'title is required to publish'};
702→    }
703→
704→    if(!draft.content){
705→        throw {status: 400, error: 'content is required to publish'};
706→    }
707→
708→    const parseData = parseTextContentSafely(draft.content);
709→    if(!parseData){
710→        throw {status: 400, error: 'failed to parse content for publish'};
711→    }
712→
713→    const embeddingBody = parseData.wholeText || '';
714→    const preview_text = parseData.slicedText || '';
715→    const thumbnail_url = parseData.firstImage?.src || null;
716→    const reading_time = Math.ceil((embeddingBody.trim().split(/\s+/).length) / 150) || 1;
717→
718→    const embeddings = await GenerateEmbeddings(trimmedTitle, embeddingBody);
719→
720→    if(!embeddings || !Array.isArray(embeddings) || embeddings.length === 0){
721→        console.error('failed to generate embeddings for draft publish');
722→        throw {status: 400, error: 'failed to generate embeddings'};
723→    }
724→
725→    const {error: updateError} = await supabase
726→        .from('journals')
727→        .update({
728→            status: 'published',
729→            published_at: new Date().toISOString(),
730→            embeddings,
731→            preview_text,
732→            thumbnail_url,
733→            reading_time,
734→            title: trimmedTitle,
735→        })
736→        .eq('id', journalId)
737→        .eq('user_id', userId);
738→
739→    if(updateError){
740→        console.error('supabase error publishing draft:', updateError.message);
741→        throw {status: 500, error: 'failed to publish draft'};
742→    }
743→
744→    // Non-fatal: send mention notifications
745→    try {
746→        const mentionedUserIds = extractMentionUserIds(draft.content);
747→        const filtered = mentionedUserIds
748→            .filter(id => id !== userId)
749→            .slice(0, 50);
750→
751→        if(filtered.length > 0){
752→            const notifRows = filtered.map(receiverId => ({
753→                sender_id: userId,
754→                receiver_id: receiverId,
755→                type: 'mention',
756→                journal_id: journalId,
757→                read: false
758→            }));
759→
760→            const {error: notifError} = await supabase
761→                .from('notifications')
762→                .insert(notifRows);
763→
764→            if(notifError){
765→                console.error('[mentions] publish draft: insert failed:', notifError.message);
766→            }
767→        }
768→    } catch (mentionErr) {
769→        console.error('[mentions] publish draft error:', mentionErr?.message || mentionErr);
770→    }
771→
772→    // Non-fatal: record publish for writing streak
773→    let streakResult = null;
774→    try {
775→        const { recordPublishForStreak } = await import('./streakService.js');
776→        streakResult = await recordPublishForStreak(userId);
777→    } catch (streakErr) {
778→        console.error('non-fatal: streak record failed:', streakErr?.message || streakErr);
779→    }
780→
781→    return { success: true, streakResult };
782→}
