 41→const formatTimeAgo = (date) => {
 42→    if (!date) return '';
 43→    const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
 44→    if (seconds < 60) return 'just now';
 45→    const minutes = Math.floor(seconds / 60);
 46→    if (minutes < 60) return `${minutes}m ago`;
 47→    const hours = Math.floor(minutes / 60);
 48→    return `${hours}h ago`;
 49→};
 50→
 51→const EditorInner = ({title, onclose, onCloseOnSave, addUploadImagesPath, setWordCount, wordCount, promptId = null, draftId = null, onDraftIdCreated}) => {
 52→    const [editor] = useLexicalComposerContext();
 53→    const [editorState, setEditorState] = useState(null);
 54→    const [hasContent, setHasContent] = useState(false);
 55→    const [isSending, setIsSending] = useState(false);
 56→
 57→    // Draft state
 58→    const draftIdRef = useRef(draftId);
 59→    const [saveStatus, setSaveStatus] = useState(draftId ? 'saved' : null); // null | 'saving' | 'saved' | 'unsaved'
 60→    const [lastSavedAt, setLastSavedAt] = useState(draftId ? new Date() : null);
 61→    const [hasChanges, setHasChanges] = useState(false);
 62→    const saveTimerRef = useRef(null);
 63→    const [, forceUpdate] = useState(0);
 64→
 65→    const {session, user} = useAuth();
 66→
 67→    const queryClient = useQueryClient();
 68→    const userId = user?.userData?.[0]?.id || null;
 69→
 70→    // Keep draftIdRef in sync
 71→    useEffect(() => {
 72→        draftIdRef.current = draftId;
 73→    }, [draftId]);
 74→
 75→    // Tick the "saved X ago" display every 30s
 76→    useEffect(() => {
 77→        if (!lastSavedAt) return;
 78→        const interval = setInterval(() => forceUpdate(n => n + 1), 30000);
 79→        return () => clearInterval(interval);
 80→    }, [lastSavedAt]);
 81→
 82→    const invalidateCreatedJournalQueries = useCallback(async() => {
 83→        const invalidations = [
 84→            queryClient.invalidateQueries({queryKey: ['journals'], refetchType: 'active'}),
 85→            queryClient.invalidateQueries({queryKey: ['journals-following'], refetchType: 'active'}),
 86→            queryClient.invalidateQueries({queryKey: ['journals-for-you'], refetchType: 'active'}),
 87→            queryClient.invalidateQueries({queryKey: ['journals-search'], refetchType: 'active'}),
 88→            queryClient.invalidateQueries({queryKey: ['journals-suggestions'], refetchType: 'active'}),
 89→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'}),
 90→        ];
 91→
 92→        if(userId){
 93→            invalidations.push(
 94→                queryClient.invalidateQueries({queryKey: ['userJournals', userId], refetchType: 'active'}),
 95→                queryClient.invalidateQueries({queryKey: ['streak', userId], refetchType: 'active'})
 96→            );
 97→        }
 98→
 99→        await Promise.allSettled(invalidations);
100→    }, [queryClient, userId]);
101→
102→    const handleSaveDraft = useCallback(async(showFeedback = true) => {
103→        if (!editorState || !session?.access_token) return;
104→        if (showFeedback) setSaveStatus('saving');
105→
106→        try {
107→            const result = await saveDraft(session.access_token, {
108→                content: editorState,
109→                title: title || '',
110→                draftId: draftIdRef.current || null,
111→                prompt_id: promptId || null,
112→            });
113→
114→            if (result?.id && !draftIdRef.current) {
115→                draftIdRef.current = result.id;
116→                if (onDraftIdCreated) onDraftIdCreated(result.id);
117→            }
118→
119→            setHasChanges(false);
120→            setSaveStatus('saved');
121→            setLastSavedAt(new Date());
122→            queryClient.invalidateQueries({queryKey: ['journal-drafts'], refetchType: 'active'});
123→        } catch (error) {
124→            console.error('Failed to save draft:', error);
125→            setSaveStatus('unsaved');
126→        }
127→    }, [editorState, session?.access_token, title, promptId, onDraftIdCreated, queryClient]);
128→
129→    // Auto-save every 30 seconds when there are changes
130→    useEffect(() => {
131→        if (!hasChanges || !editorState) return;
132→
133→        if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
134→        saveTimerRef.current = setTimeout(() => {
135→            handleSaveDraft(false);
136→        }, 30000);
137→
138→        return () => {
139→            if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
140→        };
141→    }, [editorState, hasChanges, handleSaveDraft]);
142→
143→    const handleClickPublish = async(e, title) => {
144→        e.stopPropagation();
145→        setIsSending(true);
146→
147→        try {
148→            // If we have a draft, publish it
149→            if (draftIdRef.current) {
150→                // Save latest content first
151→                await saveDraft(session.access_token, {
152→                    content: editorState,
153→                    title: title || '',
154→                    draftId: draftIdRef.current,
155→                });
156→
157→                await publishDraft(session.access_token, draftIdRef.current);
158→            } else {
159→                // Direct publish (no draft exists) — use existing save-journal flow
160→                const formdata = new FormData();
161→                if(title && editorState){
162→                    formdata.append('title', title);
163→                    formdata.append('content', editorState);
164→                }
165→                if(promptId){
166→                    formdata.append('prompt_id', promptId);
167→                }
168→                await saveJournal(session?.access_token, formdata);
169→            }
170→
171→            await invalidateCreatedJournalQueries();
172→            setHasContent(false);
173→            onCloseOnSave();
174→            addUploadImagesPath([]);
175→        } catch (error) {
176→            console.error("Error publishing journal:", error);
177→        } finally {
178→            setIsSending(false);
179→        }
180→    }
181→
182→    const onchange = useCallback((state) => {
183→        const jsonb = JSON.stringify(state.toJSON());
184→        setEditorState(jsonb)
185→        setHasChanges(true);
186→        if (saveStatus === 'saved') setSaveStatus('unsaved');
187→
188→        state.read(() => {
189→            const root = $getRoot();
190→
191→            const children = root.getChildren();
192→
193→            const hasEnoughParagraphNodes = children.length > 1
194→            const hasParargraphSize = children[0]?.__size > 0
195→
196→            const hasContent = hasParargraphSize || hasEnoughParagraphNodes
197→            setHasContent(hasContent);
198→
199→            // Calculate word count
200→            const text = root.getTextContent().trim();
201→            const words = text ? text.split(/\s+/).length : 0;
202→            setWordCount(words);
203→        })
204→    }, [setWordCount, saveStatus])
205→
206→    const renderSaveStatus = () => {
207→        if (!saveStatus) return null;
208→
209→        let statusText = '';
210→        let statusClass = 'editor-save-status';
211→
212→        switch (saveStatus) {
213→            case 'saving':
214→                statusText = 'Saving...';
215→                statusClass += ' editor-save-status--saving';
216→                break;
217→            case 'saved':
218→                statusText = lastSavedAt ? `Saved ${formatTimeAgo(lastSavedAt)}` : 'Saved';
219→                statusClass += ' editor-save-status--saved';
220→                break;
221→            case 'unsaved':
222→                statusText = 'Unsaved changes';
223→                statusClass += ' editor-save-status--unsaved';
224→                break;
225→            default:
226→                return null;
227→        }
228→
229→        return <span className={statusClass}>{statusText}</span>;
230→    };
231→
232→    return(
233→        <>
234→        {/* Toolbar above content */}
235→        <div className="toolbar-wrapper">
236→            <ToolBar addUploadedImagePath={addUploadImagesPath}/>
237→        </div>
238→
239→        {/* Bar loader directly under toolbar */}
240→        <div className="editor-loader-wrapper">
241→            {isSending && (
242→                <BarLoader loading={isSending} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
243→            )}
244→        </div>
245→
246→        {/* Editor content area */}
247→        <div className="editor-shell">
248→            <RichTextPlugin
249→            contentEditable={
250→            <ContentEditable
251→            className="editor-input"
252→            aria-placeholder="Write your thoughts here..."
253→            placeholder={<div className="editor-placeholder">Write your thoughts here...</div>}/>
254→            }
255→            ErrorBoundary={LexicalErrorBoundary}
256→            />
257→
258→            <ImagePlugin addUploadedImagePath={addUploadImagesPath}/>
259→            <MentionPlugin/>
260→            <HistoryPlugin/>
261→            <OnChangePlugin onChange={onchange}/>
262→
263→        </div>
264→
265→        {/* Footer: word count + save status + buttons */}
266→        <div className='editor-footer'>
267→            <div className="editor-footer-left">
268→                <span className="editor-word-count">
269→                    {wordCount} {wordCount === 1 ? 'word' : 'words'}
270→                </span>
271→                {renderSaveStatus()}
272→            </div>
273→            <div className="editor-footer-actions">
274→                <button
275→                    disabled={!hasContent || isSending}
276→                    onClick={() => handleSaveDraft(true)}
277→                    className={hasContent && !isSending ? 'editor-draft-bttn' : 'editor-draft-bttn-disabled'}
278→                >
279→                    Save Draft
280→                </button>
281→                <button
282→                    disabled={!title || !hasContent || isSending}
283→                    onClick={(e) => handleClickPublish(e, title)}
284→                    className={title && hasContent && !isSending ? 'editor-save-bttn' : 'editor-save-bttn-disabled'}
285→                >
286→                    Publish
287→                </button>
288→            </div>
289→        </div>
290→        </>
291→    )
292→}
293→
294→export default EditorInner;
